for rel, content in files.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")

# Limpieza de restos antiguos que ya no se usan.
old_files = [
    ROOT / "lib/apiFootball.ts",
    ROOT / "app/api/live-scores/route.ts",
]
for path in old_files:
    if path.exists():
        path.unlink()

# Si queda la carpeta vacía de live-scores, intentamos borrarla.
live_dir = ROOT / "app/api/live-scores"
try:
    live_dir.rmdir()
except OSError:
    pass

readme = ROOT / "README.md"
if readme.exists():
    current = readme.read_text(encoding="utf-8")
    if "## V4 Premium" not in current:
        readme.write_text(current.rstrip() + "\n\n" + '## V4 Premium\n\nRediseño orientado a móvil:\n- Ranking con estado inicial, próximo partido, podio y lista limpia.\n- Partidos con hora española prioritaria, estado, resultado y desplegable de nombres por 1/X/2.\n- Pronósticos como quiniela individual, sin repetir "pendiente" innecesariamente.\n- Navegación inferior con pestaña activa.\n- Limpieza visual tipo app móvil premium.\n' + "\n", encoding="utf-8")

